INSERT INTO "public"."commands" ("id", "exam", "category", "windows", "linux") VALUES (1, 'core2', 'Network Diagnostics', '{"cmd":"ipconfig","example":"ipconfig /all","description":"Displays IP address, subnet mask, and default gateway for all network adapters. Use /all for full details."}', '{"cmd":"ip addr  /  ifconfig","example":"ip addr show  /  ifconfig -a","description":"Displays or configures network interface addresses. ip addr is the modern replacement for ifconfig."}'), (2, 'core2', 'Network Diagnostics', '{"cmd":"ping","example":"ping 8.8.8.8","description":"Tests connectivity to a host by sending ICMP echo requests. Useful to verify a device is reachable."}', '{"cmd":"ping","example":"ping -c 4 8.8.8.8","description":"Same as Windows but runs continuously by default. Use -c to limit count."}'), (3, 'core2', 'Network Diagnostics', '{"cmd":"tracert","example":"tracert google.com","description":"Traces the route packets take to a destination, showing each hop and latency. Helps pinpoint where a connection fails."}', '{"cmd":"traceroute","example":"traceroute google.com","description":"Same purpose as tracert. Some distros use tracepath as a no-root alternative."}'), (4, 'core2', 'Network Diagnostics', '{"cmd":"pathping","example":"pathping google.com","description":"Combines ping and tracert — sends packets to each hop over time and reports latency and packet loss per hop."}', '{"cmd":"mtr","example":"mtr google.com","description":"Real-time combination of ping and traceroute. Continuously updates hop statistics."}'), (5, 'core2', 'Network Diagnostics', '{"cmd":"nslookup","example":"nslookup google.com","description":"Queries DNS servers to resolve hostnames to IP addresses or look up DNS records."}', '{"cmd":"nslookup  /  dig","example":"dig google.com A","description":"nslookup works the same. dig is more powerful for detailed DNS record lookups."}'), (6, 'core2', 'Network Diagnostics', '{"cmd":"netstat","example":"netstat -an","description":"Displays active TCP connections, listening ports, and network statistics. Use -an to show all connections numerically."}', '{"cmd":"netstat  /  ss","example":"ss -tuln","description":"netstat works the same. ss is the modern replacement with faster output."}'), (7, 'core2', 'Network Diagnostics', '{"cmd":"arp","example":"arp -a","description":"Displays and modifies the ARP cache — the mapping of IP addresses to MAC addresses on the local network."}', '{"cmd":"arp  /  ip neigh","example":"ip neigh show","description":"arp -n shows the ARP table. ip neigh is the modern equivalent."}'), (8, 'core2', 'Network Diagnostics', '{"cmd":"hostname","example":"hostname","description":"Displays the computer''s hostname (network name)."}', '{"cmd":"hostname","example":"hostname","description":"Displays or temporarily sets the system hostname."}'), (9, 'core2', 'Network Diagnostics', '{"cmd":"nbtstat","example":"nbtstat -n","description":"Displays NetBIOS over TCP/IP statistics and name tables. Useful for troubleshooting older Windows network name resolution."}', '{"cmd":"nmblookup","example":"nmblookup -A 192.168.1.1","description":"Part of Samba — queries NetBIOS names over TCP/IP (rarely needed on modern Linux)."}'), (10, 'core2', 'File & Directory Management', '{"cmd":"dir","example":"dir C:\\\\Users","description":"Lists files and subdirectories in the current or specified directory."}', '{"cmd":"ls","example":"ls -la /home","description":"Lists directory contents. Use -la for detailed listing including hidden files."}'), (11, 'core2', 'File & Directory Management', '{"cmd":"cd","example":"cd C:\\\\Users\\\\Admin","description":"Changes the current working directory. Use cd .. to go up one level."}', '{"cmd":"cd","example":"cd /home/user","description":"Changes the current directory. cd ~ returns to the home directory."}'), (12, 'core2', 'File & Directory Management', '{"cmd":"copy  /  xcopy  /  robocopy","example":"robocopy C:\\\\src D:\\\\dst /E /COPYALL","description":"copy: basic file copy. xcopy: copies directories and attributes. robocopy: robust copy with resume, mirroring, and logging."}', '{"cmd":"cp","example":"cp -r /source /destination","description":"Copies files and directories. Use -r for recursive directory copy."}'), (13, 'core2', 'File & Directory Management', '{"cmd":"del  /  erase","example":"del C:\\\\temp\\\\*.log","description":"Deletes one or more files. Does not move to Recycle Bin — deletion is immediate."}', '{"cmd":"rm","example":"rm -r /tmp/oldfiles","description":"Removes files. Use -r to remove directories recursively. Use with caution — no trash by default."}'), (14, 'core2', 'File & Directory Management', '{"cmd":"md  /  mkdir","example":"mkdir C:\\\\Projects\\\\NewApp","description":"Creates a new directory (folder)."}', '{"cmd":"mkdir","example":"mkdir -p /opt/app/logs","description":"Creates a new directory. Use -p to create nested directories in one command."}'), (15, 'core2', 'File & Directory Management', '{"cmd":"rd  /  rmdir","example":"rd /s /q C:\\\\OldProject","description":"Removes an empty directory. Use /s to remove directory and all contents."}', '{"cmd":"rmdir  /  rm -r","example":"rm -r /var/oldapp","description":"rmdir removes empty directories. rm -r removes directories and their contents."}'), (16, 'core2', 'File & Directory Management', '{"cmd":"ren  /  rename","example":"ren oldname.txt newname.txt","description":"Renames a file or directory."}', '{"cmd":"mv","example":"mv oldname.txt newname.txt","description":"Moves or renames files and directories."}'), (17, 'core2', 'File & Directory Management', '{"cmd":"move","example":"move C:\\\\temp\\\\file.txt D:\\\\archive\\\\","description":"Moves a file from one location to another."}', '{"cmd":"mv","example":"mv /tmp/file.txt /archive/","description":"Moves files or directories. Also used to rename."}'), (18, 'core2', 'File & Directory Management', '{"cmd":"type","example":"type C:\\\\logs\\\\error.log","description":"Displays the contents of a text file directly in the terminal."}', '{"cmd":"cat","example":"cat /var/log/syslog","description":"Concatenates and displays file contents. Also used to combine files."}'), (19, 'core2', 'File & Directory Management', '{"cmd":"cls","example":"cls","description":"Clears all text from the command prompt window."}', '{"cmd":"clear","example":"clear","description":"Clears the terminal screen. Ctrl+L is the keyboard shortcut."}'), (20, 'core2', 'File & Directory Management', '{"cmd":"attrib","example":"attrib +H +S C:\\\\boot.ini","description":"Views or changes file attributes: Read-only (R), Hidden (H), System (S), Archive (A)."}', '{"cmd":"chmod  /  chattr","example":"chmod 755 script.sh","description":"chmod changes file permissions (rwx). chattr changes special file attributes (immutable, append-only)."}'), (21, 'core2', 'File & Directory Management', '{"cmd":"findstr","example":"findstr /i \\"error\\" C:\\\\logs\\\\app.log","description":"Searches for text strings in files using literal strings or regular expressions."}', '{"cmd":"grep","example":"grep -i \\"error\\" /var/log/syslog","description":"Searches for patterns in files. One of the most commonly used Linux commands."}'), (22, 'core2', 'File & Directory Management', '{"cmd":"where","example":"where python","description":"Locates and displays the path of a program or file in the system PATH."}', '{"cmd":"which  /  find","example":"which python  /  find / -name \\"*.conf\\"","description":"which shows the path of a command. find searches for files in a directory tree."}'), (23, 'core2', 'System Information & Processes', '{"cmd":"systeminfo","example":"systeminfo","description":"Displays detailed OS and hardware configuration including OS version, RAM, hotfixes installed, and network adapters."}', '{"cmd":"uname -a  /  hostnamectl","example":"uname -a","description":"uname -a shows kernel and OS info. hostnamectl shows full system and OS details on systemd systems."}'), (24, 'core2', 'System Information & Processes', '{"cmd":"winver","example":"winver","description":"Opens a GUI dialog showing the exact Windows version and build number."}', '{"cmd":"lsb_release -a  /  cat /etc/os-release","example":"lsb_release -a","description":"Displays the Linux distribution name and version."}'), (25, 'core2', 'System Information & Processes', '{"cmd":"tasklist","example":"tasklist","description":"Lists all running processes with PID, memory usage, and status."}', '{"cmd":"ps aux  /  top","example":"ps aux | grep apache","description":"ps aux lists all running processes. top shows a real-time dynamic view of processes."}'), (26, 'core2', 'System Information & Processes', '{"cmd":"taskkill","example":"taskkill /PID 1234 /F","description":"Terminates a running process by PID or image name. Use /F to force kill."}', '{"cmd":"kill  /  killall","example":"killall firefox","description":"kill sends a signal to a process by PID (kill -9 for force). killall kills by process name."}'), (27, 'core2', 'System Information & Processes', '{"cmd":"shutdown","example":"shutdown /r /t 0","description":"Shuts down, restarts, or logs off the system. /s=shutdown, /r=restart, /t=delay in seconds."}', '{"cmd":"shutdown  /  reboot","example":"shutdown -r +5 \\"Rebooting for updates\\"","description":"shutdown -h now halts immediately. reboot restarts. poweroff shuts down."}'), (28, 'core2', 'System Information & Processes', '{"cmd":"whoami","example":"whoami /priv","description":"Displays the current logged-in username including domain. Use /priv to see privileges."}', '{"cmd":"whoami","example":"whoami","description":"Displays the current effective username."}'), (29, 'core2', 'System Information & Processes', '{"cmd":"msinfo32","example":"msinfo32","description":"Opens the System Information GUI with detailed hardware, software, and component information."}', '{"cmd":"lshw  /  inxi","example":"lshw -short","description":"lshw lists hardware configuration. inxi gives a formatted hardware/system summary."}'), (30, 'core2', 'Disk Management', '{"cmd":"chkdsk","example":"chkdsk C: /f /r","description":"Checks a disk for file system errors and bad sectors. Use /f to fix errors, /r to locate bad sectors."}', '{"cmd":"fsck","example":"fsck -y /dev/sda1","description":"File system check and repair utility. Must be run on unmounted partitions."}'), (31, 'core2', 'Disk Management', '{"cmd":"diskpart","example":"diskpart  (then: list disk, select disk 0, clean)","description":"Interactive command-line tool to manage disks, partitions, and volumes. Used for formatting, shrinking, and creating partitions."}', '{"cmd":"fdisk  /  parted","example":"fdisk /dev/sda","description":"fdisk is the classic partition editor. parted supports GPT and larger disks. gdisk for GPT-specific work."}'), (32, 'core2', 'Disk Management', '{"cmd":"format","example":"format D: /FS:NTFS /Q","description":"Formats a disk or partition with a specified file system (NTFS, FAT32, exFAT)."}', '{"cmd":"mkfs","example":"mkfs.ext4 /dev/sdb1","description":"Creates a file system on a partition. Specify type with mkfs.ext4, mkfs.ntfs, mkfs.vfat, etc."}'), (33, 'core2', 'Disk Management', '{"cmd":"sfc","example":"sfc /scannow","description":"System File Checker — scans and repairs corrupted Windows system files using cached copies."}', '{"cmd":"debsums  /  rpm -V","example":"debsums -s","description":"debsums verifies installed package file integrity on Debian/Ubuntu. rpm -V verifies on RHEL/CentOS."}'), (34, 'core2', 'Disk Management', '{"cmd":"df  (not built-in)","example":"Get-PSDrive -PSProvider FileSystem","description":"Windows does not have a built-in df. Use diskpart or check via File Explorer. PowerShell: Get-PSDrive."}', '{"cmd":"df  /  du","example":"df -h  /  du -sh /var/*","description":"df shows disk space usage per mount point. du shows disk usage of files and directories."}'), (35, 'core2', 'User & Security Management', '{"cmd":"net user","example":"net user john P@ssw0rd /add","description":"Creates, modifies, or deletes local user accounts. Also displays account information."}', '{"cmd":"useradd  /  passwd","example":"useradd john && passwd john","description":"useradd creates a new user. passwd sets or changes the user''s password."}'), (36, 'core2', 'User & Security Management', '{"cmd":"net localgroup","example":"net localgroup Administrators john /add","description":"Manages local groups — add/remove users from groups like Administrators."}', '{"cmd":"groupadd  /  usermod","example":"usermod -aG sudo john","description":"groupadd creates groups. usermod -aG adds a user to a group."}'), (37, 'core2', 'User & Security Management', '{"cmd":"runas","example":"runas /user:Administrator cmd","description":"Runs a program as a different user (typically an administrator). Similar to sudo on Linux."}', '{"cmd":"sudo  /  su","example":"sudo apt update  /  su - admin","description":"sudo runs a single command as root or another user. su switches the active user session."}'), (38, 'core2', 'User & Security Management', '{"cmd":"cipher","example":"cipher /e C:\\\\SensitiveFolder","description":"Encrypts or decrypts files/folders using EFS (Encrypting File System). Also used to securely wipe free space."}', '{"cmd":"gpg  /  openssl","example":"gpg -c secret.txt","description":"gpg encrypts files using GNU Privacy Guard. openssl encrypts with various algorithms."}'), (39, 'core2', 'User & Security Management', '{"cmd":"icacls","example":"icacls C:\\\\folder /grant john:(OI)(CI)F","description":"Views and modifies NTFS file and folder permissions (ACLs)."}', '{"cmd":"chmod  /  chown","example":"chmod 644 file.txt  /  chown user:group file","description":"chmod changes file read/write/execute permissions. chown changes file owner and group."}'), (40, 'core2', 'Services & Remote Management', '{"cmd":"sc","example":"sc start wuauserv","description":"Service Control — starts, stops, creates, queries, and configures Windows services from the command line."}', '{"cmd":"systemctl","example":"systemctl restart apache2","description":"Controls systemd services — start, stop, restart, enable, disable, and check status."}'), (41, 'core2', 'Services & Remote Management', '{"cmd":"net start  /  net stop","example":"net stop \\"Windows Update\\"","description":"Starts or stops a Windows service by display name. Simpler alternative to sc."}', '{"cmd":"service","example":"service ssh restart","description":"Legacy interface to start/stop/restart services. Works alongside systemctl on many distros."}'), (42, 'core2', 'Services & Remote Management', '{"cmd":"mstsc","example":"mstsc /v:192.168.1.100","description":"Opens the Remote Desktop Connection client to connect to another Windows machine via RDP (port 3389)."}', '{"cmd":"ssh","example":"ssh user@192.168.1.100","description":"Secure Shell — encrypted remote terminal access to another machine over port 22."}'), (43, 'core2', 'Services & Remote Management', '{"cmd":"gpupdate","example":"gpupdate /force","description":"Forces an immediate refresh of Group Policy settings on the computer and user."}', '{"cmd":"(no direct equivalent)","example":"realm join domain.local","description":"Linux uses configuration files instead of Group Policy. sssd or realmd can apply domain policies in AD environments."}'), (44, 'core2', 'Services & Remote Management', '{"cmd":"gpresult","example":"gpresult /r","description":"Displays the Group Policy settings and Resultant Set of Policy (RSoP) for the current user and computer."}', '{"cmd":"(no direct equivalent)","example":"adcli info domain.local","description":"Domain-joined Linux systems can use sss_cache or adcli to query applied policies."}'), (45, 'core2', 'Package & Software Management', '{"cmd":"winget","example":"winget install VLC","description":"Windows Package Manager CLI — installs, updates, and removes software from the Microsoft Store and web repositories."}', '{"cmd":"apt  /  yum  /  dnf","example":"apt install nmap  /  dnf update","description":"apt is used on Debian/Ubuntu. yum/dnf on RHEL/CentOS/Fedora. Used to install, update, and remove packages."}'), (46, 'core2', 'Package & Software Management', '{"cmd":"msiexec","example":"msiexec /i setup.msi /quiet","description":"Installs, modifies, or removes Windows Installer (.msi) packages. Used for silent/automated installs."}', '{"cmd":"dpkg  /  rpm","example":"dpkg -i package.deb  /  rpm -ivh pkg.rpm","description":"dpkg installs .deb packages on Debian/Ubuntu. rpm installs .rpm packages on RHEL/CentOS."}'), (47, 'core2', 'Logs & Troubleshooting', '{"cmd":"eventvwr","example":"eventvwr","description":"Opens the Event Viewer GUI — view System, Application, and Security logs for error and warning events."}', '{"cmd":"journalctl","example":"journalctl -u ssh -n 50","description":"Queries the systemd journal (logs). Use -u for a specific service or -xe for errors."}'), (48, 'core2', 'Logs & Troubleshooting', '{"cmd":"sfc /scannow","example":"sfc /scannow","description":"Scans all protected Windows system files and replaces corrupted files from a cached copy."}', '{"cmd":"dmesg","example":"dmesg | grep -i error","description":"Prints the kernel ring buffer — useful for hardware errors, driver issues, and boot messages."}'), (49, 'core2', 'Logs & Troubleshooting', '{"cmd":"msconfig","example":"msconfig","description":"System Configuration tool — manage startup programs, boot options, and services. Used in Safe Mode troubleshooting."}', '{"cmd":"systemctl list-units","example":"systemctl --failed","description":"Lists all active systemd units (services, mounts, etc.). Use --failed to see only failed units."}'), (50, 'core2', 'Registry & Config Files', '{"cmd":"regedit","example":"regedit","description":"Registry Editor GUI — view and modify the Windows Registry (HKLM, HKCU, etc.). Changes take effect immediately."}', '{"cmd":"(no equivalent — uses text config files)","example":"nano /etc/ssh/sshd_config","description":"Linux stores configuration in plain text files under /etc. Common paths: /etc/ssh/sshd_config, /etc/fstab, /etc/hosts."}'), (51, 'core2', 'Registry & Config Files', '{"cmd":"reg","example":"reg query HKLM\\\\SOFTWARE\\\\Microsoft\\\\Windows\\\\CurrentVersion","description":"Command-line Registry editor — add, delete, query, export, and import registry keys without opening regedit."}', '{"cmd":"cat  /  nano  /  vi","example":"nano /etc/hosts","description":"Linux configuration is text-based. Use any text editor to view or modify config files."}'), (52, 'netplus', 'Connectivity Testing', '{"cmd":"ping","example":"ping 8.8.8.8\\nping -t 192.168.1.1","description":"Sends ICMP echo requests to test reachability and measure round-trip time. Default sends 4 packets. Use -t for continuous ping."}', '{"cmd":"ping","example":"ping -c 4 8.8.8.8\\nping -c 10 -i 0.5 192.168.1.1","description":"Same as Windows but runs continuously by default. Use -c to limit packet count and -i to set interval."}'), (53, 'netplus', 'Connectivity Testing', '{"cmd":"tracert","example":"tracert google.com\\ntracert -d 10.0.0.1","description":"Traces the route to a destination, showing each hop''s IP and round-trip time. Uses ICMP. Useful for isolating where connectivity fails."}', '{"cmd":"traceroute","example":"traceroute google.com\\nmtr --report google.com","description":"Same as tracert but uses UDP by default. Use -I for ICMP or -T for TCP. mtr combines ping + traceroute in real time."}'), (54, 'netplus', 'Connectivity Testing', '{"cmd":"pathping","example":"pathping google.com\\npathping -n 10.0.0.1","description":"Combines tracert and ping — traces route and measures packet loss and latency at each hop over a period of time."}', '{"cmd":"mtr","example":"mtr google.com\\nmtr --report --report-cycles 10 google.com","description":"My Traceroute — combines traceroute and ping, updating results in real time. Shows packet loss per hop."}'), (55, 'netplus', 'Address & Interface Config', '{"cmd":"ipconfig","example":"ipconfig /all\\nipconfig /release\\nipconfig /renew\\nipconfig /flushdns","description":"Displays IP address, subnet mask, and default gateway. /all shows DNS servers, MAC address, DHCP server, and lease times."}', '{"cmd":"ip addr / ifconfig","example":"ip addr show\\nip addr add 192.168.1.10/24 dev eth0\\nifconfig -a","description":"ip addr is the modern tool for showing/configuring interface addresses. ifconfig is legacy. ip link shows interface state."}'), (56, 'netplus', 'Address & Interface Config', '{"cmd":"arp -a","example":"arp -a\\narp -d 192.168.1.1","description":"Displays the ARP cache — the table mapping IP addresses to MAC addresses. Useful to verify L2 reachability and spot ARP spoofing."}', '{"cmd":"arp / ip neigh","example":"arp -n\\nip neigh show\\nip neigh flush dev eth0","description":"arp -n displays ARP cache. ip neigh show is the modern equivalent and shows neighbor state (REACHABLE, STALE, FAILED)."}'), (57, 'netplus', 'Address & Interface Config', '{"cmd":"route print","example":"route print\\nroute add 10.0.0.0 mask 255.0.0.0 192.168.1.1","description":"Displays the IP routing table showing destination networks, gateway, interface, and metric. Use route add/delete to modify."}', '{"cmd":"ip route / route -n","example":"ip route show\\nip route add 10.0.0.0/8 via 192.168.1.1\\nroute -n","description":"ip route show displays the routing table. ip route add adds a static route. route -n is the legacy command."}'), (58, 'netplus', 'DNS Troubleshooting', '{"cmd":"nslookup","example":"nslookup google.com\\nnslookup -type=MX google.com\\nnslookup 8.8.8.8","description":"Queries DNS servers to resolve hostnames or IPs. Enter interactive mode with no arguments. Use ''server'' to switch DNS servers."}', '{"cmd":"dig","example":"dig google.com\\ndig @8.8.8.8 google.com MX\\ndig +short google.com A","description":"Domain Information Groper — more detailed DNS query tool than nslookup. Shows full DNS response including TTL and authority records."}'), (59, 'netplus', 'DNS Troubleshooting', '{"cmd":"ipconfig /flushdns","example":"ipconfig /flushdns\\nipconfig /displaydns","description":"Clears the local DNS resolver cache. Use when stale DNS entries cause name resolution failures after a DNS change."}', '{"cmd":"systemd-resolve --flush-caches","example":"sudo systemd-resolve --flush-caches\\nresolvectl flush-caches\\nsudo service nscd restart","description":"Flushes the systemd-resolved DNS cache. Alternatively restart nscd or use resolvectl flush-caches on newer systems."}'), (60, 'netplus', 'Port & Connection Analysis', '{"cmd":"netstat","example":"netstat -ano\\nnetstat -ano | findstr :443\\nnetstat -r","description":"Displays active connections, listening ports, and routing tables. -ano shows all connections with PIDs. -b shows the executable."}', '{"cmd":"ss / netstat","example":"ss -tuln\\nss -antp | grep :80\\nnetstat -tulnp","description":"ss (socket statistics) is the modern replacement for netstat. -tuln shows all TCP/UDP listening ports. netstat -tulnp also works."}'), (61, 'netplus', 'Port & Connection Analysis', '{"cmd":"telnet","example":"telnet 192.168.1.1 80\\ntelnet smtp.example.com 25","description":"Tests TCP connectivity to a specific port on a remote host (telnet client must be enabled). Useful for verifying firewall rules."}', '{"cmd":"nc (netcat) / telnet","example":"nc -zv 192.168.1.1 80\\nnc -zv 192.168.1.1 20-25\\ntelnet 192.168.1.1 443","description":"netcat (nc) is more flexible — tests TCP/UDP port connectivity, transfers data, and creates simple servers for testing."}'), (62, 'netplus', 'Port & Connection Analysis', '{"cmd":"nmap (third-party)","example":"nmap 192.168.1.0/24\\nnmap -sV -p 1-1024 192.168.1.1\\nnmap -O 10.0.0.1","description":"Network mapper — scans hosts and open ports, detects OS and service versions. Not built-in; installed separately. Used in Network+ troubleshooting."}', '{"cmd":"nmap","example":"nmap -sS 192.168.1.0/24\\nnmap -sU -p 53,161 10.0.0.1\\nnmap -A 192.168.1.1","description":"Same as Windows. Common flags: -sS (SYN scan), -sU (UDP scan), -sV (version detection), -O (OS detection), -A (aggressive scan)."}'), (63, 'netplus', 'Packet Capture & Analysis', '{"cmd":"Wireshark / netsh trace","example":"netsh trace start capture=yes\\nnetsh trace stop\\n# Wireshark display filter:\\nip.addr==192.168.1.1 && tcp.port==443","description":"Wireshark is the GUI packet analyzer for Network+. netsh trace start captures natively. Display filters narrow results by protocol, IP, or port."}', '{"cmd":"tcpdump","example":"tcpdump -i eth0 -n\\ntcpdump -i eth0 port 80 -w capture.pcap\\ntcpdump -r capture.pcap","description":"Command-line packet capture tool. Captures traffic on an interface and optionally writes to a .pcap file for analysis in Wireshark."}'), (64, 'netplus', 'Wireless Diagnostics', '{"cmd":"netsh wlan","example":"netsh wlan show all\\nnetsh wlan show profiles\\nnetsh wlan show interfaces","description":"Manages wireless profiles and shows WLAN interface details. show all displays SSIDs, signal strength, BSSID, channel, and security type."}', '{"cmd":"iwconfig / iw","example":"iwconfig wlan0\\niw dev wlan0 scan | grep -E ''SSID|signal''\\niwlist wlan0 scanning","description":"iwconfig shows/configures wireless interface parameters. iw is the modern replacement. iwlist scan scans for nearby access points."}'), (65, 'netplus', 'Remote Access', '{"cmd":"ssh","example":"ssh admin@192.168.1.1\\nssh -p 2222 user@server\\nssh -i ~/.ssh/id_rsa user@host","description":"Built-in since Windows 10. Establishes encrypted remote shell sessions (port 22). ssh-keygen generates key pairs for key-based auth."}', '{"cmd":"ssh","example":"ssh admin@192.168.1.1\\nscp file.txt user@host:/tmp/\\nsftp user@192.168.1.10","description":"Same as Windows. Use -L for local port forwarding, -R for remote, -D for SOCKS proxy. scp and sftp transfer files securely."}');